static void OnStartup() {
    FPDF_InitLibrary();
#ifdef _WIN32
    ghmodule = LoadLibrary(L"Riched20.dll");
#endif
    
    g_mime_init();
    cmark_gfm_core_extensions_ensure_registered();
}

void PluginMain(PA_long32 selector, PA_PluginParameters params) {
    
	try
	{
        switch(selector)
        {
            case kInitPlugin :
            case kServerInitPlugin :
                OnStartup();
                break;
             
            case kDeinitPlugin :
            case kServerDeinitPlugin :
                OnExit();
                break;
                
			// --- Universal Document Parser
            
			case 1 :
				Extract(params);
				break;
            case 2 :
                Extract_SET_OPTION(params);
                break;
        }

	}
	catch(...)
	{

	}
}

#pragma mark 4D.File

static bool _object_to_path(PA_ObjectRef f, std::string& path, int type) {
 
    if(f != NULL) {
        C_TEXT pp;
        pp.setUTF8String((const uint8_t *)"platformPath", 12);
        PA_Unistring PLATFORMPATH = PA_CreateUnistring((PA_Unichar *)pp.getUTF16StringPtr());//PA_DisposeUnistring
        PA_VariableKind vk = PA_GetObjectPropertyType(f, &PLATFORMPATH);
        if(vk == eVK_Unistring) {
            PA_Variable p = PA_GetObjectProperty(f, &PLATFORMPATH);//PA_ClearVariable
            PA_Variable cbparams[2];
            cbparams[0] = PA_CreateVariable(eVK_Unistring);//PA_DisposeUnistring
            cbparams[1] = PA_CreateVariable(eVK_Longint);//PA_DisposeUnistring
            PA_Unistring platformPath = PA_GetStringVariable(p);
            PA_SetStringVariable(&cbparams[0], &platformPath);
            PA_SetLongintVariable(&cbparams[1], 1/*fk platform path*/);
            PA_Variable folder = PA_ExecuteCommandByID(type, cbparams, 2);
            PA_ClearVariable(&cbparams[0]);
            PA_ClearVariable(&cbparams[1]);
            PA_ClearVariable(&p);
            
#if VERSIONMAC
            pp.setUTF8String((const uint8_t *)"path", 4);
            PA_Unistring PATH = PA_CreateUnistring((PA_Unichar *)pp.getUTF16StringPtr());//PA_DisposeUnistring
            PA_Variable _p = PA_GetObjectProperty(PA_GetObjectVariable(folder), &PATH);//PA_ClearVariable
            platformPath = PA_GetStringVariable(_p);
            PA_DisposeUnistring(&PATH);
            PA_ClearVariable(&_p);
#endif
            C_TEXT t;
            t.setUTF16String(&platformPath);
            CUTF8String u8;
            t.copyUTF8String(&u8);
            path = std::string((const char *)u8.c_str(), u8.size());
        }
        PA_DisposeUnistring(&PLATFORMPATH);
        return (vk == eVK_Unistring);
    }
    
    return false;
}

static bool file_object_to_data(PA_ObjectRef f, std::vector<uint8_t>& data) {
    
    if(f != NULL) {
        
        const int cmd_4D = 1709;
        PA_Variable prm_4D[1];
        PA_Variable _4D = PA_ExecuteCommandByID(cmd_4D, prm_4D, 0);
        
        const int cmd_OB_Get = 1224;
        PA_Variable prm_OB_Get[2];
        prm_OB_Get[0] = _4D;
        prm_OB_Get[1] = PA_CreateVariable(eVK_Unistring);
        C_TEXT pp;
        pp.setUTF8String((const uint8_t *)"Blob", 4);
        PA_Unistring BLOB = PA_CreateUnistring((PA_Unichar *)pp.getUTF16StringPtr());
        PA_SetStringVariable(&prm_OB_Get[1], &BLOB);//DO NOT call PA_DisposeUnistring
        PA_Variable _4D_Blob = PA_ExecuteCommandByID(cmd_OB_Get, prm_OB_Get, 2);
        PA_ClearVariable(&prm_OB_Get[1]);//BLOB belongs to variable. no need to dispose
        
        const int cmd_OB_Instance_of = 1731;
        PA_Variable prm_OB_Instance_of[2];
        prm_OB_Instance_of[0] = PA_CreateVariable(eVK_Object);
        prm_OB_Instance_of[1] = _4D_Blob;
        PA_SetObjectVariable(&prm_OB_Instance_of[0], f);
        PA_Variable status = PA_ExecuteCommandByID(cmd_OB_Instance_of, prm_OB_Instance_of, 2);
        bool isBlob = PA_GetBooleanVariable(status);
        if(isBlob) {

            pp.setUTF8String((const uint8_t *)"size", 4);
            PA_Unistring SIZE = PA_CreateUnistring((PA_Unichar *)pp.getUTF16StringPtr());//PA_DisposeUnistring
            PA_Variable _s = PA_GetObjectProperty(f, &SIZE);
            PA_long32 size = PA_GetRealVariable(_s);
            PA_DisposeUnistring(&SIZE);
            PA_ClearVariable(&_s);
            
            PA_Variable blob = PA_CreateVariable(eVK_Blob);
            
            const int cmd_COPY_BLOB = 558;
            PA_Variable prm_COPY_BLOB[5];
            prm_COPY_BLOB[0] = prm_OB_Instance_of[0];
            prm_COPY_BLOB[1] = blob;
            prm_COPY_BLOB[2] = PA_CreateVariable(eVK_Longint);
            prm_COPY_BLOB[3] = PA_CreateVariable(eVK_Longint);
            prm_COPY_BLOB[4] = PA_CreateVariable(eVK_Longint);
            
            PA_SetLongintVariable(&prm_COPY_BLOB[2], 0);
            PA_SetLongintVariable(&prm_COPY_BLOB[3], 0);
            PA_SetLongintVariable(&prm_COPY_BLOB[4], size);
            
            PA_ExecuteCommandByID(cmd_COPY_BLOB, prm_COPY_BLOB, 5);
            
            data.resize(size);
            PA_GetBlobVariable(blob, &data[0]);

            PA_ClearVariable(&prm_COPY_BLOB[1]);//blob
            PA_ClearVariable(&prm_COPY_BLOB[2]);
            PA_ClearVariable(&prm_COPY_BLOB[3]);
            PA_ClearVariable(&prm_COPY_BLOB[4]);
        }
        
        PA_ClearVariable(&prm_OB_Instance_of[0]);
        return isBlob;
    }
    
    return false;
}

